1	type Quote = { premium: number };
2	type Item = { type: string; cursed?: boolean; enchantment?: number };
3	
4	const PROCESSING_FEE = 5;
5	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
6	  sword: 100,
7	  staff: 80,
8	  amulet: 60,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	const ALIKE_BLOCK_SIZE = 3;
14	const ALIKE_BLOCK_PREMIUM = 60;
15	const CURSE_SURCHARGE_RATE = 0.5;
16	const HIGH_ENCHANTMENT_THRESHOLD = 5;
17	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
18	const LOYALTY_YEARS_THRESHOLD = 2;
19	const LOYALTY_DISCOUNT_RATE = 0.2;
20	
21	const basePremiumFor = (item: Item): number =>
22	  BASE_PREMIUM_BY_TYPE[item.type];
23	
24	const curseSurchargeRateFor = (item: Item): number =>
25	  item.cursed ? CURSE_SURCHARGE_RATE : 0;
26	
27	const enchantmentSurchargeRateFor = (item: Item): number =>
28	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
29	    ? HIGH_ENCHANTMENT_SURCHARGE_RATE
30	    : 0;
31	
32	const totalSurchargeRateFor = (item: Item): number =>
33	  curseSurchargeRateFor(item) + enchantmentSurchargeRateFor(item);
34	
35	const itemPremiumFor = (item: Item): number =>
36	  basePremiumFor(item) * (1 + totalSurchargeRateFor(item));
37	
38	const sumItemPremiums = (items: Item[]): number =>
39	  items.reduce((sum, item) => sum + itemPremiumFor(item), 0);
40	
41	const isAlikeBlock = (items: Item[]): boolean =>
42	  items.length === ALIKE_BLOCK_SIZE &&
43	  items.every((item) => item.type === items[0].type);
44	
45	const componentsPremium = (items: Item[]): number =>
46	  isAlikeBlock(items) ? ALIKE_BLOCK_PREMIUM : sumItemPremiums(items);
47	
48	const loyaltyDiscountRateFor = (customer?: { yearsWithMHPCO: number }): number =>
49	  (customer?.yearsWithMHPCO ?? 0) >= LOYALTY_YEARS_THRESHOLD
50	    ? LOYALTY_DISCOUNT_RATE
51	    : 0;
52	
53	export const quote = (input: { customer?: { yearsWithMHPCO: number }; items: Item[] }): Quote => {
54	  const componentsTotal = componentsPremium(input.items);
55	  const policyTotal = componentsTotal * (1 - loyaltyDiscountRateFor(input.customer));
56	  return { premium: policyTotal + PROCESSING_FEE };
57	};
58	
59	export const claim = (_input: unknown): unknown => undefined;
